#include <stdio.h>

#define MAX_SIZE 10

void printArray(const int arr[], int size) {
    for (int i = 0; i < size; i++) {
        printf("%d ", arr[i]);

    }
    printf("\n");
}

int linearSearch(const int arr[], int size, int target) {
    for (int i = 0; i < size; i++) {
        if (arr[i] == target) return i;
    }
    return -1;
}

int insertElement(int arr[], int *size, int element, int capacity, int position) {
    if (*size >= capacity || position < 0 || position > *size) return 0;
    for (int i = *size; i > position; i--) {
        arr[i] = arr[i - 1];
    }
    arr[position] = element;
    (*size)++;
    return 1;
}

int deleteElement(int arr[], int *size, int position) {
    if (position < 0 || position >= *size) return 0;
    for (int i = position; i < *size - 1; i++) {
        arr[i] = arr[i + 1];
    }
    (*size)--;
    return 1;
}

int main(void) {
    int scores[MAX_SIZE] = {85, 92, 78, 90};
    int currentSize = 4;

    printf("Initial array: ");
    printArray(scores, currentSize);

    int target = 92;
    int foundIndex = linearSearch(scores, currentSize, target);
    printf("Search for %d: Found at index %d\n", target, foundIndex);

    if (insertElement(scores, &currentSize, 99, MAX_SIZE, 2)) {
        printf("After insertion at index 2: ");
        printArray(scores, currentSize);
    }

    if (deleteElement(scores, &currentSize, 1)) {
        printf("After deletion at index 1: ");
        printArray(scores, currentSize);
    }

    return 0;
}

